import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    // Helper: validates that the returned index is truly a peak.
    // Out-of-bounds neighbors are treated as -infinity.
    private boolean isValidPeak(int[] nums, int idx) {
        if (idx < 0 || idx >= nums.length) return false;
        int left  = (idx > 0)                ? nums[idx - 1] : Integer.MIN_VALUE;
        int right = (idx < nums.length - 1) ? nums[idx + 1] : Integer.MIN_VALUE;
        return nums[idx] > left && nums[idx] > right;
    }

    @Test
    void singlePeakInMiddle() {
        // [1,2,3,1] — only peak is at index 2
        int[] nums = {1, 2, 3, 1};
        int result = new Solution().findPeakElement(nums);
        assertTrue(isValidPeak(nums, result),
                "Expected a valid peak index but got " + result);
    }

    @Test
    void twoPeaksAnyValid() {
        // [1,2,1,3,5,6,4] — peaks at index 1 (value 2) and index 5 (value 6)
        int[] nums = {1, 2, 1, 3, 5, 6, 4};
        int result = new Solution().findPeakElement(nums);
        assertTrue(isValidPeak(nums, result),
                "Expected a valid peak index but got " + result);
    }

    @Test
    void singleElement() {
        // Single element is always a peak
        int[] nums = {42};
        int result = new Solution().findPeakElement(nums);
        assertTrue(isValidPeak(nums, result),
                "Expected a valid peak index but got " + result);
    }

    @Test
    void peakAtFirstIndex() {
        // [2,1] — first element is a peak (no left neighbor)
        int[] nums = {2, 1};
        int result = new Solution().findPeakElement(nums);
        assertTrue(isValidPeak(nums, result),
                "Expected a valid peak index but got " + result);
    }

    @Test
    void peakAtLastIndex() {
        // [1,2] — last element is a peak (no right neighbor)
        int[] nums = {1, 2};
        int result = new Solution().findPeakElement(nums);
        assertTrue(isValidPeak(nums, result),
                "Expected a valid peak index but got " + result);
    }

    @Test
    void strictlyIncreasingArray() {
        // [1,2,3,4,5] — only the last element is a peak
        int[] nums = {1, 2, 3, 4, 5};
        int result = new Solution().findPeakElement(nums);
        assertTrue(isValidPeak(nums, result),
                "Expected a valid peak index but got " + result);
    }

    @Test
    void strictlyDecreasingArray() {
        // [5,4,3,2,1] — only the first element is a peak
        int[] nums = {5, 4, 3, 2, 1};
        int result = new Solution().findPeakElement(nums);
        assertTrue(isValidPeak(nums, result),
                "Expected a valid peak index but got " + result);
    }
}
